var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"실종자들이라고요?","JPN":"失踪者？","ENG":"Missing people?","TWN":"失蹤人口？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"네, 저희가 일전의 전투에서 상대했던 자들의 신원은 모두 10여년 전부터 실종 후 사망처리 된 자들이었습니다.","JPN":"はい、私たちがこの前の戦闘で戦った相手は全員10年程前に失踪し、後に死亡処理された者たちでした。","ENG":"Yes. The foes we faced in our recent battles were all people who went missing for 10 years and were thought to be dead.","TWN":"是的，我們之前交手過的那些人，全都是在十幾年前失蹤，最後以死亡結案的人口。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그 외에 일관된 점은 그들 대부분이 북방합의체 소속이라는 점이지요.","JPN":"それ以外にも一貫しているところは、彼らのほとんどが北方合意体の所属だということです。","ENG":"Another commonality we found was that they were affiliated with the Northern Union.","TWN":"除此之外，他們還有一個共通點，就是大部分都隸屬於北方和議會。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"북방합의체……","JPN":"北方合意体……","ENG":"The Northern Union...","TWN":"北方和議會……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 폐쇄적인 나라의 실종자들이 왜 이런 곳에 있던 걸까요?","JPN":"そんな閉鎖的な国の失踪者がどうしてこんなところにいたのでしょうか。","ENG":"Why would missing people from that closed-off country suddenly appeared here?","TWN":"那個封閉國家的失蹤人口怎麼會出現在這裡呢？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"북방합의체의 과학기관은 침식현상연구를 빌미로 인체실험을 자행하는 등 예전부터 악명이 높았습니다.","JPN":"北方合意体の科学機関は侵食現象の研究を口実に人体実験をするなど、昔から悪名が高かったのです。","ENG":"The Northern Union's science department is infamous for secretly carrying out human experiments in the name of studying the Counterside Effect.","TWN":"北方和議會的科學機構會以人體實驗私自進行侵蝕現象研究等等，因此從以前便是惡名昭彰。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"결국 관리국의 직접적인 제재 이후로 한동안 잠잠해졌지만, 얼마 후 북방합의체에 근간을 둔 다수의 태스크포스가 창설되었고요.","JPN":"管理局が直接制裁を加えてからはしばらく静かでしたが、ほどなくして北方合意体に根をもつ多数のタスクフォースが創設されました。","ENG":"Eventually, the Administration stepped in and they allegedly stopped their practices. However, a number of TASKFORCEs based on the Northern Union started to emerge.","TWN":"在管理局出手制裁後，曾經沉寂一段時間，但不久後便出現許多來自北方和議會的特遣勢力。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"신생 태스크포스 노아…… 로군요.","JPN":"新生タスクフォース・ノア……ですね。","ENG":"That's... TASKFORCE NOA...","TWN":"新興特遣勢力諾亞……嗎。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그들은 처음부터 태스크포스를 다른 목적으로 운영하고 있었던 거였어요.","JPN":"彼らは最初からタスクフォースを別目的で運営していたのですね。","ENG":"They were operating this TASKFORCE for a different purpose from the beginning.","TWN":"他們一開始經營特遣勢力的目的就是另有所圖。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키의 탈출 당일 일어난 침식사태 또한 그들의 소행이라는 정황이 확인됐습니다.","JPN":"覇吐の脱出当日に起きた侵食事態もまた彼らの仕業であることも確認済みです。","ENG":"It was also confirmed that they are connected to the Corruption disaster that broke out on the day of Habaki's escape.","TWN":"目前也已經確定，幅木逃獄當天發生的侵蝕事件也是他們所為。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그들이 이곳을 떠나지 않은 목적이 치후유님을 상대로 실험하는 것이었다면……","JPN":"彼らがここを離れなかった目的が千冬様を相手に実験することだとしたら……","ENG":"If their reasoning for staying here is to experiment on Miss Chifuyu...","TWN":"若他們沒離開這裡的目的是要對千冬進行實驗……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하바키가 찾는 것은 나나하라 가문의 힘…… 치후유와 제가 목적이겠죠.","JPN":"覇吐が探しているのは七原家の力……千冬と私なのでしょう。","ENG":"Then Habaki's objective is to obtain the power of the Nanahara family. Which means Chifuyu and me.","TWN":"幅木要找的是七原家族的力量……那目標就是千冬和我。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 바람의 목소리를 들을 수 있었다면, 이런 참변이 일어나기 전에 막았을 텐데.","JPN":"私が風の声を聞くことができていたら、このような惨事が起きる前に止められたのでしょうが。","ENG":"If I could only hear the voice of wind, all of this could have been prevented.","TWN":"要是我能夠聽到風聲，就能夠預防這種慘劇發生。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그날 당주님의 선택으로 저희의 운명은 바뀌었고, 역신 오로치의 부활을 막을 수 있었습니다.","JPN":"あの日、ご当主様の選択で私たちの運命は変わり、疫病神オロチの復活を止めることができました。","ENG":"That day, your choice changed the fate of all of us. You were able to stop Plague God Orochi's resurgence, Lady Nanahara.","TWN":"那天堂主的選擇改變了我們的命運，還阻止了瘟神大蛇復活。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"신력을 사용한 대가가 바람의 목소리를 앗아가는 것이라 하더라도…… 저는 그 선택이 잘못되었다고 생각하지 않습니다.","JPN":"神力を使った代償が風の声を奪われることであっても……私はその選択が間違っていたとは思えません。","ENG":"Even if the price was losing the voice of wind... I do not think you made the wrong decision.","TWN":"就算使用神力的代價是會失去風聲……但我也不認為那是個錯誤的決定。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유와 약속했어요. 책임을 지기 위해 치르는 희생 같은 건 더는 하지 말자고.","JPN":"千冬と約束したのです。責任を取るための犠牲などはもうやめようと。","ENG":"I made a promise with Chifuyu. That we would not make any more sacrifices out of responsibility.","TWN":"我有答應千冬，不會再因為責任而造成犧牲。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 내가 정하는 선택들은…… 결국 누군가의 희생을 치르고 마네요.","JPN":"ですが、私が決断をすると……結局誰かが犠牲となってしまうのですね。","ENG":"But the decisions I make... Someone ends up paying for it in the end.","TWN":"但我所做的決定……最終還是造成某人的犧牲。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};